const raw = $input.first().json.content?.[0]?.text || '{}';

let parsed = {};
try {
  const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = { raw_analysis: raw };
}

return [{ json: {
  status: 'completed',
  workflow: '15_user_analytics_digest',
  summary: parsed.summary || 'Analytics digest complete',
  total_users: parsed.total_users || 0,
  new_signups: parsed.new_signups || {},
  active_users: parsed.active_users || {},
  role_distribution: parsed.role_distribution || [],
  engagement_metrics: parsed.engagement_metrics || {},
  conversion_funnel: parsed.conversion_funnel || {},
  trends: parsed.trends || [],
  growth_recommendations: parsed.growth_recommendations || [],
  alerts: parsed.alerts || [],
  report: parsed,
  completedAt: new Date().toISOString()
} }];
